Since I am a text-based AI, I cannot directly generate a binary 3D file (like an `.obj` or `.fbx`) that you can download. However, I can provide you with **complete, runnable code** to render a 3D house using **Three.js**, the most popular JavaScript library for 3D graphics on the web.

You can copy the code below, save it as an `.html` file, and open it in any modern browser to see the result.

### Option 1: Interactive 3D House (Web Browser)
This code creates a low-poly house with a roof, walls, a door, and a window. It includes lighting, shadows, and orbit controls so you can rotate around the house.

**Instructions:**
1. Copy the code block below.
2. Create a new file on your computer named `house.html`.
3. Paste the code into that file and save it.
4. Double-click `house.html` to open it in your browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x4a3c31 }); // Dark wood
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallGeo = new THREE.BoxGeometry(10, 6, 8);
        const walls = new THREE.Mesh(wallGeo, wallMaterial);
        walls.position.y = 3;
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // Roof
        const roofGeo = new THREE.ConeGeometry(9, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 2, 4.1); // Slightly in front of wall
        door.castShadow = true;
        houseGroup.add(door);

        // Window
        const winGeo = new THREE.BoxGeometry(2, 2, 0.1);
        const windowMesh = new THREE.Mesh(winGeo, windowMaterial);
        windowMesh.position.set(0, 5, 4.05);
        houseGroup.add(windowMesh);

        // Chimney
        const chimGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimGeo, wallMaterial);
        chimney.position.set(4, 10, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### Option 2: Python (Blender API)
If you prefer Python and have **Blender** installed, you can use the `bpy` module to generate a house programmatically.

**Prerequisites:**
1. Install Blender.
2. Install the Blender Python module (usually included with Blender).
3. Run this script inside Blender's Text Editor (File > Scripting > New).

```python
import bpy
import math

# Clear existing objects
for obj in bpy.data.objects:
    bpy.data.objects.remove(obj, do_unlink=True)

# Create a simple house
def create_house():
    # 1. Floor
    bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 0, 0))
    floor = bpy.context.active_object
    floor.scale = (10, 10, 1)
    floor.name = "Floor"

    # 2. Walls
    bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 0, 3))
    wall = bpy.context.active_object
    wall.scale = (10, 6, 8)
    wall.name = "Walls"

    # 3. Roof (Cone)
    bpy.ops.mesh.primitive_cone_add(radius1=9, depth=4, location=(0, 0, 8))
    roof = bpy.context.active_object
    roof.name = "Roof"
    # Rotate cone to align with walls
    roof.rotation_euler = (0, math.pi/4, 0)

    # 4. Door
    bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 2, 4.1))
    door = bpy.context.active_object
    door.scale = (2, 4, 0.2)
    door.name = "Door"

create_house()

# Apply Materials
for obj in bpy.data.objects:
    mat = bpy.data.materials.new(name=obj.name + " Mat")
    mat.use_nodes = True
    bsdf = obj.material_slots[0].material.node_tree.nodes["Principled BSDF"]
    bsdf.inputs["Base Color"].default_value = (0.8, 0.8, 0.8, 1.0) # Grey
